const data = $input.first().json;
const dailyPrecip = data.daily?.precipitation_sum || [];
const soilMoisture = data.daily?.soil_moisture_0_to_7cm_mean || [];
const deepSoil = data.daily?.soil_moisture_7_to_28cm_mean || [];

// Landslide Susceptibility Index
// Based on: cumulative 7-day rainfall + current soil saturation
const past7DayRain = dailyPrecip.slice(0, 7).reduce((s, v) => s + (v || 0), 0);
const next3DayRain = dailyPrecip.slice(7, 10).reduce((s, v) => s + (v || 0), 0);
const avgSoilMoisture = soilMoisture.length
  ? soilMoisture.slice(0, 5).reduce((s, v) => s + (v || 0), 0) / Math.max(1, soilMoisture.slice(0, 5).length)
  : 0.3;
const avgDeepSoil = deepSoil.length
  ? deepSoil.slice(0, 5).reduce((s, v) => s + (v || 0), 0) / Math.max(1, deepSoil.slice(0, 5).length)
  : 0.3;

// LSI score (0-100)
const rainScore = Math.min(50, past7DayRain * 0.8);
const futureRainBoost = Math.min(20, next3DayRain * 1.5);
const soilScore = (avgSoilMoisture + avgDeepSoil) * 25; // 0-50 range
const lsi = rainScore + soilScore + futureRainBoost;

let severity = 'Low';
let probability = 0.05;
let action = 'monitor';

if (lsi >= 80 || (past7DayRain >= 80 && avgSoilMoisture >= 0.7)) {
  severity = 'Critical'; probability = 0.80; action = 'close_at_risk_roads';
} else if (lsi >= 60 || (past7DayRain >= 50 && avgSoilMoisture >= 0.5)) {
  severity = 'High'; probability = 0.60; action = 'issue_landslide_warning';
} else if (lsi >= 40 || past7DayRain >= 30) {
  severity = 'Medium'; probability = 0.35; action = 'issue_landslide_advisory';
}

return [{ json: {
  incidentType: 'landslide',
  severity,
  probability,
  lsi: Math.round(lsi * 10) / 10,
  past7DayRainMm: Math.round(past7DayRain * 10) / 10,
  next3DayRainMm: Math.round(next3DayRain * 10) / 10,
  avgSoilMoisture: Math.round(avgSoilMoisture * 1000) / 1000,
  action,
  shouldAlert: severity !== 'Low',
  timestamp: new Date().toISOString()
}}];
